CREATE TABLE publication (id uuid NOT NULL,publication_key varchar(100) NOT NULL,content_status varchar(20) NOT NULL,publication_stage varchar(20) NOT NULL,doi varchar(255) NULL,external_url varchar(2048) NULL,published_on date NULL,year integer NOT NULL,cover_media_id uuid NULL,sort_order integer NOT NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_publication PRIMARY KEY(id),CONSTRAINT uq_publication_key UNIQUE(publication_key),CONSTRAINT ck_publication_key CHECK(btrim(publication_key)<>''),CONSTRAINT ck_publication_status CHECK(content_status IN('DRAFT','PUBLISHED','ARCHIVED')),CONSTRAINT ck_publication_stage CHECK(publication_stage IN('PREPRINT','ACCEPTED','IN_PRESS','PUBLISHED')),CONSTRAINT ck_publication_year CHECK(year BETWEEN 1000 AND 9999),CONSTRAINT ck_publication_doi CHECK(doi IS NULL OR doi ~* '^10\\.[0-9]{4,9}/[-._;()/:a-z0-9]+$'),CONSTRAINT ck_publication_order CHECK(sort_order>=0),CONSTRAINT fk_publication_media FOREIGN KEY(cover_media_id) REFERENCES media_asset(id) ON DELETE RESTRICT,CONSTRAINT fk_publication_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_publication_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_publication_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL);
CREATE UNIQUE INDEX ux_publication_doi_ci ON publication(lower(doi)) WHERE doi IS NOT NULL AND deleted_at IS NULL; CREATE INDEX ix_publication_status_year_order ON publication(content_status,year DESC,sort_order,id);
CREATE TABLE publication_translation (id uuid NOT NULL,publication_id uuid NOT NULL,language_code varchar(2) NOT NULL,title varchar(255) NOT NULL,slug varchar(255) NOT NULL,abstract_text text NULL,authors_display text NULL,venue_display text NULL,seo_title varchar(255) NULL,seo_description varchar(500) NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_publication_translation PRIMARY KEY(id),CONSTRAINT uq_publication_translation_locale UNIQUE(publication_id,language_code),CONSTRAINT ck_publication_translation_locale CHECK(language_code IN('fa','en')),CONSTRAINT ck_publication_translation_title CHECK(btrim(title)<>''),CONSTRAINT ck_publication_translation_slug CHECK(btrim(slug)<>''),CONSTRAINT fk_publication_translation_publication FOREIGN KEY(publication_id) REFERENCES publication(id) ON DELETE CASCADE,CONSTRAINT fk_publication_translation_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_publication_translation_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_publication_translation_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL); CREATE UNIQUE INDEX ux_publication_translation_slug ON publication_translation(language_code,lower(slug)) WHERE deleted_at IS NULL;
CREATE TABLE resume_entry (id uuid NOT NULL,entry_type varchar(30) NOT NULL,status varchar(20) NOT NULL,started_on date NOT NULL,ended_on date NULL,is_current boolean NOT NULL DEFAULT false,sort_order integer NOT NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_resume_entry PRIMARY KEY(id),CONSTRAINT ck_resume_entry_type CHECK(entry_type IN('EDUCATION','EXPERIENCE','RESEARCH','AWARD','CERTIFICATION')),CONSTRAINT ck_resume_entry_status CHECK(status IN('DRAFT','PUBLISHED','ARCHIVED')),CONSTRAINT ck_resume_entry_dates CHECK(ended_on IS NULL OR ended_on>=started_on),CONSTRAINT ck_resume_entry_current CHECK(NOT is_current OR ended_on IS NULL),CONSTRAINT ck_resume_entry_order CHECK(sort_order>=0),CONSTRAINT fk_resume_entry_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_resume_entry_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_resume_entry_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL); CREATE INDEX ix_resume_entry_type_status_order ON resume_entry(entry_type,status,sort_order,started_on DESC,id);
CREATE TABLE resume_entry_translation (id uuid NOT NULL,resume_entry_id uuid NOT NULL,language_code varchar(2) NOT NULL,title varchar(255) NOT NULL,organization varchar(255) NOT NULL,location varchar(255) NULL,summary text NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_resume_entry_translation PRIMARY KEY(id),CONSTRAINT uq_resume_entry_translation_locale UNIQUE(resume_entry_id,language_code),CONSTRAINT ck_resume_entry_translation_locale CHECK(language_code IN('fa','en')),CONSTRAINT ck_resume_entry_translation_title CHECK(btrim(title)<>''),CONSTRAINT ck_resume_entry_translation_org CHECK(btrim(organization)<>''),CONSTRAINT fk_resume_entry_translation_entry FOREIGN KEY(resume_entry_id) REFERENCES resume_entry(id) ON DELETE CASCADE,CONSTRAINT fk_resume_entry_translation_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_resume_entry_translation_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_resume_entry_translation_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL);
CREATE TABLE resume_document (id uuid NOT NULL,language_code varchar(2) NOT NULL,media_asset_id uuid NOT NULL,status varchar(20) NOT NULL,published_at timestamptz NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_resume_document PRIMARY KEY(id),CONSTRAINT ck_resume_document_locale CHECK(language_code IN('fa','en')),CONSTRAINT ck_resume_document_status CHECK(status IN('DRAFT','PUBLISHED','ARCHIVED')),CONSTRAINT ck_resume_document_publish CHECK(status<>'PUBLISHED' OR published_at IS NOT NULL),CONSTRAINT fk_resume_document_media FOREIGN KEY(media_asset_id) REFERENCES media_asset(id) ON DELETE RESTRICT,CONSTRAINT fk_resume_document_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_resume_document_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_resume_document_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL); CREATE UNIQUE INDEX ux_resume_document_current_locale ON resume_document(language_code) WHERE deleted_at IS NULL; CREATE INDEX ix_resume_document_locale_status ON resume_document(language_code,status);
